import React from "react";
import styleLearningLink from "./Learning.module.css";

const Learning = (props) => {
  return (
    <div className={styleLearningLink.link}>
      <NavLink
        to={props.to}
        className={({ isActive }) =>
          isActive ? `${styleLearningLink.active}` : `${styleLearningLink.link}`
        }
      >
        {props.text}
      </NavLink>
    </div>
  );
};

export default Learning;
